<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller;use Illuminate\Http\Request;use App\Services\{AuthService,UserService,CategoryService,CulinaryPlaceService,ReviewService,ReservationService,NotificationService};
class ReviewController extends Controller{public function store(Request $r,ReviewService $s){$data=$r->validate(['culinary_place_id'=>'required|exists:culinary_places,id','rating'=>'required|integer|min:1|max:5','review_text'=>'nullable']);$data['user_id']=$r->user()->id;return response()->json($s->create($data),201);} public function update(Request $r,\App\Models\Review $review,ReviewService $s){$this->authorize('update',$review);return $s->update($review->id,$r->validate(['rating'=>'sometimes|integer|min:1|max:5','review_text'=>'nullable']));} public function destroy(\App\Models\Review $review,ReviewService $s){$this->authorize('delete',$review);$s->delete($review->id);return response()->noContent();} public function report(Request $r){return \App\Models\ReviewReport::create($r->validate(['review_id'=>'required|exists:reviews,id','reason'=>'required','description'=>'nullable'])+['user_id'=>$r->user()->id]);} public function reply(Request $r){return \App\Models\ReviewReply::create($r->validate(['review_id'=>'required|exists:reviews,id','reply_text'=>'required'])+['owner_id'=>$r->user()->id]);}}
